1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Conway's Game of Life - nextGeneration", () => {
5	  it("should return empty array for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should preserve a block pattern [(0,0),(1,0),(0,1),(1,1)] as still life", () => {
15	    const input: Array<[number, number]> = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const sortCells = (cells: Array<[number, number]>) =>
17	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
18	    expect(sortCells(nextGeneration(input))).toEqual(sortCells(input));
19	  });
20	  it("should transform a vertical blinker [(0,0),(0,1),(0,2)] into a horizontal blinker [(-1,1),(0,1),(1,1)]", () => {
21	    const input: Array<[number, number]> = [[0, 0], [0, 1], [0, 2]];
22	    const expected: Array<[number, number]> = [[-1, 1], [0, 1], [1, 1]];
23	    const sortCells = (cells: Array<[number, number]>) =>
24	      [...cells].sort((a, b) => a[0] - b[0] || a[1] - b[1]);
25	    expect(sortCells(nextGeneration(input))).toEqual(sortCells(expected));
26	  });
27	  it.todo("should kill a live cell with 4 live neighbors (overpopulation)");
28	  it.todo("should bring a dead cell with exactly 3 live neighbors to life (reproduction)");
29	  it.todo("should handle negative coordinates correctly");
30	});
