1	type Cell = [number, number];
2	
3	const neighborOffsets: Array<Cell> = [
4	  [-1, -1], [0, -1], [1, -1],
5	  [-1, 0],           [1, 0],
6	  [-1, 1],  [0, 1],  [1, 1],
7	];
8	
9	const cellKey = (x: number, y: number): string => `${x},${y}`;
10	
11	const survives = (currentlyAlive: boolean, liveNeighborCount: number): boolean =>
12	  (currentlyAlive && liveNeighborCount === 2) || liveNeighborCount === 3;
13	
14	export const nextGeneration = (liveCells: Array<Cell>): Array<Cell> => {
15	  const liveSet = new Set(liveCells.map(([x, y]) => cellKey(x, y)));
16	  const isAlive = (x: number, y: number): boolean => liveSet.has(cellKey(x, y));
17	
18	  const countLiveNeighbors = (x: number, y: number): number =>
19	    neighborOffsets.reduce(
20	      (count, [dx, dy]) => count + (isAlive(x + dx, y + dy) ? 1 : 0),
21	      0,
22	    );
23	
24	  const candidates = new Map<string, Cell>();
25	  for (const [x, y] of liveCells) {
26	    candidates.set(cellKey(x, y), [x, y]);
27	    for (const [dx, dy] of neighborOffsets) {
28	      candidates.set(cellKey(x + dx, y + dy), [x + dx, y + dy]);
29	    }
30	  }
31	
32	  const result: Array<Cell> = [];
33	  for (const [, [x, y]] of candidates) {
34	    if (survives(isAlive(x, y), countLiveNeighbors(x, y))) {
35	      result.push([x, y]);
36	    }
37	  }
38	
39	  return result;
40	};
