it("should kill a live cell with 4 live neighbors (overpopulation)", () => {
  const input: Array<[number, number]> = [[0, 0], [1, 0], [2, 0], [1, 1], [0, 2], [1, 2], [2, 2]];
  const result = nextGeneration(input);
  expect(result.some(([x, y]) => x === 1 && y === 1)).toBe(false);
});
